import re

def detect_unsafe_code(run):
    output = run.last_error or run.outputs[0].logs if run.outputs else ''

    dangerous_patterns = [
        r'rm\s+-rf',
        r'curl\s+[^\s]+\.\{[^}]+\}',
        r'nc\s+[^\s]+\s+[^\s]+',
        r'/etc/passwd',
        r'whoami',
        r'wget\s+http'
    ]

    for pattern in dangerous_patterns:
        if re.search(pattern, output, re.IGNORECASE):
            return {'alert': 'UNSAFE_CODE_DETECTED', 'pattern': pattern}
    return None

def validate_function_schema(run, assistant_tools):
    alerts = []
    if not run.required_action:
        return alerts

    for tool_call in run.required_action.submit_tool_outputs.tool_calls:
        func_name = tool_call.function.name
        func_schema = next(t for t in assistant_tools if t.function.name == func_name)

        try:
            args = json.loads(tool_call.function.arguments)
            # Check required properties
            required = func_schema.function.parameters.properties
            missing = [k for k in func_schema.function.parameters.required if k not in args]
            if missing:
                alerts.append({'error': 'MISSING_REQUIRED_ARGS', 'missing': missing})
        except json.JSONDecodeError:
            alerts.append({'error': 'INVALID_JSON_ARGS'})

    return alerts

async function detectThreadBloat(threadId: string, client: OpenAI): Promise<boolean> {
  const messages = await client.beta.threads.messages.list(threadId);
  const messageCount = messages.data.length;
  const tokenEstimate = messageCount * 4000; // Conservative estimate

  if (messageCount > 100 || tokenEstimate > 120000) {
    console.warn(`Thread ${threadId} bloat detected: ${messageCount} msgs, ~${tokenEstimate} tokens`);
    return true;
  }
  return false;
}

