def safe_code_interpreter_guard(run):
    if run.status == 'completed' and run.outputs:
        output = run.outputs[0].logs
        unsafe_patterns = [r'rm\s+-rf', r'/etc/', r'curl.*exec']

        for pattern in unsafe_patterns:
            if re.search(pattern, output, re.IGNORECASE):
                # Fail the run and require human intervention
                run.submit_tool_outputs(tool_outputs=[
                    {
                        'tool_call_id': 'code_interpreter',
                        'output': 'SECURITY_VIOLATION: Unsafe code detected. Human review required.'
                    }
                ])
                return False
    return True

function validateToolArgs(toolCalls: any[], tools: any[]): boolean {
  for (const toolCall of toolCalls) {
    const toolDef = tools.find(t => t.function?.name === toolCall.function.name);
    if (!toolDef) continue;

    try {
      const args = JSON.parse(toolCall.function.arguments);
      const schema = toolDef.function.parameters;

      // Validate required fields
      for (const reqField of schema.required || []) {
        if (!(reqField in args)) {
          throw new Error(`Missing required field: ${reqField}`);
        }
      }
    } catch (e) {
      console.error('Invalid tool args:', e.message);
      return false;
    }
  }
  return true;
}

